import{_ as o,o as t,c as i,aw as r}from"./chunks/framework.DLufY-ao.js";const p=JSON.parse('{"title":"Схемы для написания промптов (CRISPE, RISEN, APE)","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/dev-commit/theory/methodology-dev/ai/schemes.md","filePath":"wiki/dev-commit/theory/methodology-dev/ai/schemes.md"}'),a={name:"wiki/dev-commit/theory/methodology-dev/ai/schemes.md"};function s(l,e,n,c,g,d){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="схемы-для-написания-промптов-crispe-risen-ape" tabindex="-1">Схемы для написания промптов (CRISPE, RISEN, APE) <a class="header-anchor" href="#схемы-для-написания-промптов-crispe-risen-ape" aria-label="Permalink to &quot;Схемы для написания промптов (CRISPE, RISEN, APE)&quot;">​</a></h1><h2 id="crispe" tabindex="-1">CRISPE <a class="header-anchor" href="#crispe" aria-label="Permalink to &quot;CRISPE&quot;">​</a></h2><ul><li><strong>Capacity</strong> — в какой «роли» выступает модель (эксперт, ревьюер, учитель).</li><li><strong>Request</strong> — что именно нужно сделать (одна чёткая задача).</li><li><strong>Importance</strong> — насколько это важно и зачем нужно.</li><li><strong>Specificity</strong> — детали: формат, объём, ограничения, примеры.</li><li><strong>Personality</strong> — тон ответа (формальный, дружелюбный, нейтральный).</li><li><strong>Experiment</strong> — попробовать разные формулировки и сравнить результаты.</li></ul><blockquote><p>Удобно, когда нужно задать и контекст, и тон, и уровень детализации. Когда нужны тон и эксперименты</p></blockquote><h2 id="risen" tabindex="-1">RISEN <a class="header-anchor" href="#risen" aria-label="Permalink to &quot;RISEN&quot;">​</a></h2><ul><li><strong>Role</strong> — роль модели (например: senior-разработчик, тестировщик).</li><li><strong>Instruction</strong> — основная инструкция (что сделать).</li><li><strong>Steps</strong> — пошаговый план или порядок действий.</li><li><strong>End goal</strong> — желаемый итог (критерий «готово»).</li><li><strong>Narrowing</strong> — сужение: что не делать, какие технологии/форматы использовать.</li></ul><blockquote><p>Фокус на пошаговости и чётком критерии завершения. Когда важен пошаговый план</p></blockquote><h2 id="ape" tabindex="-1">APE <a class="header-anchor" href="#ape" aria-label="Permalink to &quot;APE&quot;">​</a></h2><ul><li><strong>Action</strong> — действие (напиши, исправь, объясни, сравни).</li><li><strong>Purpose</strong> — зачем: цель и контекст использования результата.</li><li><strong>Expectation</strong> — ожидания: формат, длина, стиль, что должно быть в ответе.</li></ul><blockquote><p>Минимальная схема из трёх частей: что сделать, зачем и в каком виде. Быстрый чеклист</p></blockquote>',10)])])}const m=o(a,[["render",s]]);export{p as __pageData,m as default};
